const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const session = require('express-session');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

app.use(express.json());
app.use(session({
  secret: 'your_secret_key',
  resave: false,
  saveUninitialized: true,
}));

let players = {};

io.use((socket, next) => {
  const sessionId = socket.handshake.headers['session-id'];
  if (!sessionId || !players[sessionId]) {
    return next(new Error('Authentication error'));
  }
  socket.sessionId = sessionId;
  return next();
});

io.on('connection', (socket) => {
  const sessionId = socket.sessionId;
  socket.on('playerMove', (moveData) => {
    if (validateMove(moveData)) {
      io.emit('updateMove', moveData);
    }
  });

  socket.on('submitScore', ({ username, score }) => {
    if (players[sessionId]) {
      players[sessionId].score = score;
      updateLeaderboard(username, score);
    }
  });

  socket.on('disconnect', () => {
    delete players[sessionId];
  });
});

app.post('/login', (req, res) => {
  const { username } = req.body;
  if (username) {
    const sessionId = crypto.randomBytes(16).toString('hex');
    players[sessionId] = { username, score: 0 };
    res.json({ sessionId });
  } else {
    res.status(400).send('Invalid username');
  }
});

